{"command":"@'
$ErrorActionPreference = 'Stop'

$repo = 'c:\Users\Evrim\Desktop\FRP\Convergence\game_hub5'
$sourcePath = Join-Path $repo 'references\Basic_Rules4.txt'
$outputPath = Join-Path $repo 'json_refs\basic_rules.json'

function Convert-ToSnakeCase {
  param([string]$Text)

  if ([string]::IsNullOrWhiteSpace($Text)) {
    return ''
  }

  $normalized = $Text.ToLowerInvariant()
  $normalized = [regex]::Replace($normalized, '[^a-z0-9]+', '_')
  $normalized = $normalized.Trim('_')
  return $normalized
}

function Parse-HeadingMeta {
  param([string]$HeadingText)

  $qualifierMatches = [regex]::Matches($HeadingText, '\((?<q>[^)]*)\)')
  $qualifiers = New-Object System.Collections.ArrayList
  $rawQualifiers = New-Object System.Collections.ArrayList

  foreach ($match in $qualifierMatches) {
    $rawText = $match.Groups['q'].Value.Trim()
    if ($rawText.Length -gt 0) {
      $null = $rawQualifiers.Add($rawText)
      foreach ($part in ($rawText -split ',')) {
        $trimmedPart = $part.Trim()
        if ($trimmedPart.Length -gt 0) {
          $null = $qualifiers.Add((Convert-ToSnakeCase $trimmedPart))
        }
      }
    }
  }

  $title = [regex]::Replace($HeadingText, '\s*\([^)]*\)', '')
  $title = $title.Trim()

  return [pscustomobject][ordered]@{
    title = $title
    qualifiers = @($qualifiers)
    raw_qualifiers = @($rawQualifiers)
  }
}

function Resolve-Authority {
  param(
    [string[]]$RawQualifiers,
    [string]$ParentAuthority
  )

  $upperQualifiers = @($RawQualifiers | ForEach-Object { $_.ToUpperInvariant() })
  foreach ($qualifier in $upperQualifiers) {
    if ($qualifier -match 'NON-AUTHORITATIVE') {
      return [pscustomobject][ordered]@{ authority = 'non_authoritative'; authority_source = 'explicit' }
    }
  }

  foreach ($qualifier in $upperQualifiers) {
    if ($qualifier -match 'AUTHORITATIVE') {
      return [pscustomobject][ordered]@{ authority = 'authoritative'; authority_source = 'explicit' }
    }
  }

  return [pscustomobject][ordered]@{ authority = $ParentAuthority; authority_source = 'inherited' }
}

function New-SectionNode {
  param(
    [string]$Number,
    [string]$HeadingText,
    [string]$RawHeading,
    [string]$ParentAuthority
  )

  $meta = Parse-HeadingMeta $HeadingText
  $authorityInfo = Resolve-Authority -RawQualifiers $meta.raw_qualifiers -ParentAuthority $ParentAuthority

  return [pscustomobject][ordered]@{
    id = $Number
    number = $Number
    title = $meta.title
    slug = Convert-ToSnakeCase $meta.title
    raw_heading = $RawHeading
    authority = $authorityInfo.authority
    authority_source = $authorityInfo.authority_source
    qualifiers = @($meta.qualifiers)
    entries = New-Object System.Collections.ArrayList
    subsections = New-Object System.Collections.ArrayList
  }
}

function New-BulletEntry {
  param([string]$RawLine)

  $text = $RawLine -replace '^\s*-\s*', ''
  return [pscustomobject][ordered]@{
    type = 'bullet'
    text = $text
    raw = $RawLine
    children = New-Object System.Collections.ArrayList
  }
}

function New-StatementEntry {
  param([string]$TrimmedLine)

  return [pscustomobject][ordered]@{
    type = 'statement'
    text = $TrimmedLine
    raw = $TrimmedLine
  }
}

function New-LabeledRuleEntry {
  param(
    [string]$TrimmedLine,
    [string]$Label,
    [string]$Value
  )

  return [pscustomobject][ordered]@{
    type = 'labeled_rule'
    text = $TrimmedLine
    raw = $TrimmedLine
    label = Convert-ToSnakeCase $Label
    value = $Value.Trim()
  }
}

function Split-TableRow {
  param([string]$Line)

  $trimmed = $Line.Trim()
  $trimmed = $trimmed.Trim('|')
  return @($trimmed -split '\|' | ForEach-Object { $_.Trim() })
}

function Convert-ScalarValue {
  param([string]$Value)

  if ($Value -match '^-?\d+$') {
    return [int]$Value
  }

  return $Value
}

function Parse-RangeBounds {
  param([string]$Value)

  if ($Value -match '^(?<min>\d+)\+$') {
    return [pscustomobject][ordered]@{ min = [int]$Matches['min']; max = $null }
  }

  if ($Value -match '^(?<min>\d+)-(?<max>\d+)$') {
    return [pscustomobject][ordered]@{ min = [int]$Matches['min']; max = [int]$Matches['max'] }
  }

  return $null
}

$lines = Get-Content -Path $sourcePath
if ($lines.Count -eq 0) {
  throw 'Source file is empty.'
}

$document = [pscustomobject][ordered]@{
  source = [pscustomobject][ordered]@{
    path = 'references/Basic_Rules4.txt'
    filename = 'Basic_Rules4.txt'
    title = $lines[0]
  }
  preamble = New-Object System.Collections.ArrayList
  sections = New-Object System.Collections.ArrayList
}

$sectionStack = New-Object System.Collections.ArrayList
$bulletStack = New-Object System.Collections.ArrayList
$currentNode = $null

for ($index = 1; $index -lt $lines.Count; $index++) {
  $line = $lines[$index]
  $trimmed = $line.Trim()

  if ([string]::IsNullOrWhiteSpace($trimmed)) {
    $bulletStack.Clear()
    continue
  }

  if ($line -match '^\s*===\s*(?<inner>.+?)\s*===\s*$') {
    $bulletStack.Clear()
    $inner = $Matches['inner']
    if ($inner -notmatch '^(?<number>\d+(?:\.\d+)*)\.?\s+(?<heading>.+)$') {
      throw "Unable to parse top-level heading: $line"
    }

    $number = $Matches['number']
    $headingText = $Matches['heading']
    $node = New-SectionNode -Number $number -HeadingText $headingText -RawHeading $line -ParentAuthority $null

    $sectionStack.Clear()
    $null = $document.sections.Add($node)
    $null = $sectionStack.Add($node)
    $currentNode = $node
    continue
  }

  if ($trimmed -match '^(?<number>\d+(?:\.\d+)*)(?:\.)?\s+(?<heading>.+)$') {
    $bulletStack.Clear()
    $number = $Matches['number']
    $headingText = $Matches['heading']
    $depth = ($number -split '\.').Count

    if ($depth -le 1) {
      throw "Unexpected non-top-level heading depth for: $line"
    }

    while ($sectionStack.Count -ge $depth) {
      $sectionStack.RemoveAt($sectionStack.Count - 1)
    }

    if ($sectionStack.Count -ne ($depth - 1)) {
      throw "Missing parent section for heading: $line"
    }

    $parentNode = $sectionStack[$sectionStack.Count - 1]
    $node = New-SectionNode -Number $number -HeadingText $headingText -RawHeading $line -ParentAuthority $parentNode.authority
    $null = $parentNode.subsections.Add($node)
    $null = $sectionStack.Add($node)
    $currentNode = $node
    continue
  }

  if ($trimmed -match '^\|') {
    if ($null -eq $currentNode) {
      throw "Encountered a table outside of any section: $line"
    }

    $bulletStack.Clear()
    $tableLines = New-Object System.Collections.ArrayList
    while ($index -lt $lines.Count -and $lines[$index].Trim().StartsWith('|')) {
      $null = $tableLines.Add($lines[$index])
      $index++
    }
    $index--

    if ($tableLines.Count -lt 3) {
      throw 'Encountered a malformed table.'
    }

    $headers = @(Split-TableRow $tableLines[0] | ForEach-Object { Convert-ToSnakeCase $_ })
    $rows = New-Object System.Collections.ArrayList

    for ($rowIndex = 2; $rowIndex -lt $tableLines.Count; $rowIndex++) {
      $cells = Split-TableRow $tableLines[$rowIndex]
      $row = [ordered]@{}
      for ($cellIndex = 0; $cellIndex -lt $headers.Count; $cellIndex++) {
        $header = $headers[$cellIndex]
        $cellValue = if ($cellIndex -lt $cells.Count) { $cells[$cellIndex] } else { '' }
        $row[$header] = Convert-ScalarValue $cellValue
      }

      if ($row.Contains('xp_used_range')) {
        $bounds = Parse-RangeBounds -Value ([string]$row['xp_used_range'])
        if ($null -ne $bounds) {
          $row['xp_used_min'] = $bounds.min
          $row['xp_used_max'] = $bounds.max
        }
      }

      $null = $rows.Add([pscustomobject]$row)
    }

    $tableEntry = [pscustomobject][ordered]@{
      type = 'table'
      title = $currentNode.title
      columns = @($headers)
      rows = @($rows)
    }

    $null = $currentNode.entries.Add($tableEntry)
    continue
  }

  if ($line -match '^(?<indent>\s*)-\s+(?<text>.+)$') {
    $entry = New-BulletEntry -RawLine $line
    $indent = $Matches['indent'].Length

    while ($bulletStack.Count -gt 0 -and $bulletStack[$bulletStack.Count - 1].indent -ge $indent) {
      $bulletStack.RemoveAt($bulletStack.Count - 1)
    }

    if ($bulletStack.Count -gt 0) {
      $parentBullet = $bulletStack[$bulletStack.Count - 1].entry
      $null = $parentBullet.children.Add($entry)
    }
    elseif ($null -ne $currentNode) {
      $null = $currentNode.entries.Add($entry)
    }
    else {
      $null = $document.preamble.Add($entry)
    }

    $null = $bulletStack.Add([pscustomobject]@{ indent = $indent; entry = $entry })
    continue
  }

  $bulletStack.Clear()
  $trimmedLine = $line.Trim()

  if ($trimmedLine -match '^(?<label>[^:]+):\s*(?<value>.+)$') {
    $entry = New-LabeledRuleEntry -TrimmedLine $trimmedLine -Label $Matches['label'] -Value $Matches['value']
  }
  else {
    $entry = New-StatementEntry -TrimmedLine $trimmedLine
  }

  if ($null -ne $currentNode) {
    $null = $currentNode.entries.Add($entry)
  }
  else {
    $null = $document.preamble.Add($entry)
  }
}

$json = $document | ConvertTo-Json -Depth 100
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($outputPath, $json + "`n", $utf8NoBom)

Write-Output "Wrote $outputPath"
