{"command":"@'
const fs = require('fs');
const path = require('path');

const repo = 'c:/Users/Evrim/Desktop/FRP/Convergence/game_hub5';
const sourcePath = path.join(repo, 'references', 'Basic_Rules4.txt');
const outputPath = path.join(repo, 'json_refs', 'basic_rules.json');

function toSnakeCase(text) {
  if (!text || !text.trim()) {
    return '';
  }
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function parseHeadingMeta(headingText) {
  const rawQualifiers = [];
  const qualifiers = [];
  const qualifierPattern = /\(([^)]*)\)/g;
  let match;

  while ((match = qualifierPattern.exec(headingText)) !== null) {
    const rawText = match[1].trim();
    if (!rawText) {
      continue;
    }
    rawQualifiers.push(rawText);
    for (const part of rawText.split(',')) {
      const trimmedPart = part.trim();
      if (trimmedPart) {
        qualifiers.push(toSnakeCase(trimmedPart));
      }
    }
  }

  const title = headingText.replace(/\s*\([^)]*\)/g, '').trim();
  return { title, qualifiers, rawQualifiers };
}

function resolveAuthority(rawQualifiers, parentAuthority) {
  const upperQualifiers = rawQualifiers.map((item) => item.toUpperCase());
  if (upperQualifiers.some((item) => item.includes('NON-AUTHORITATIVE'))) {
    return { authority: 'non_authoritative', authority_source: 'explicit' };
  }
  if (upperQualifiers.some((item) => item.includes('AUTHORITATIVE'))) {
    return { authority: 'authoritative', authority_source: 'explicit' };
  }
  return { authority: parentAuthority, authority_source: 'inherited' };
}

function newSectionNode(number, headingText, rawHeading, parentAuthority) {
  const meta = parseHeadingMeta(headingText);
  const authorityInfo = resolveAuthority(meta.rawQualifiers, parentAuthority);
  return {
    id: number,
    number,
    title: meta.title,
    slug: toSnakeCase(meta.title),
    raw_heading: rawHeading,
    authority: authorityInfo.authority,
    authority_source: authorityInfo.authority_source,
    qualifiers: meta.qualifiers,
    entries: [],
    subsections: []
  };
}

function newBulletEntry(rawLine) {
  return {
    type: 'bullet',
    text: rawLine.replace(/^\s*-\s*/, ''),
    raw: rawLine,
    children: []
  };
}

function newStatementEntry(trimmedLine) {
  return {
    type: 'statement',
    text: trimmedLine,
    raw: trimmedLine
  };
}

function newLabeledRuleEntry(trimmedLine, label, value) {
  return {
    type: 'labeled_rule',
    text: trimmedLine,
    raw: trimmedLine,
    label: toSnakeCase(label),
    value: value.trim()
  };
}

function splitTableRow(line) {
  return line
    .trim()
    .replace(/^\|/, '')
    .replace(/\|$/, '')
    .split('|')
    .map((cell) => cell.trim());
}

function convertScalarValue(value) {
  return /^-?\d+$/.test(value) ? Number(value) : value;
}

function parseRangeBounds(value) {
  let match = value.match(/^(\d+)\+$/);
  if (match) {
    return { min: Number(match[1]), max: null };
  }
  match = value.match(/^(\d+)-(\d+)$/);
  if (match) {
    return { min: Number(match[1]), max: Number(match[2]) };
  }
  return null;
}

const rawSource = fs.readFileSync(sourcePath, 'utf8');
const lines = rawSource.replace(/^\uFEFF/, '').split(/\r?\n/);
if (!lines.length || !lines[0]) {
  throw new Error('Source file is empty.');
}

const document = {
  source: {
    path: 'references/Basic_Rules4.txt',
    filename: 'Basic_Rules4.txt',
    title: lines[0]
  },
  preamble: [],
  sections: []
};

const sectionStack = [];
const bulletStack = [];
let currentNode = null;

for (let index = 1; index < lines.length; index += 1) {
  const line = lines[index];
  const trimmed = line.trim();

  if (!trimmed) {
    bulletStack.length = 0;
    continue;
  }

  let match = line.match(/^\s*===\s*(.+?)\s*===\s*$/);
  if (match) {
    bulletStack.length = 0;
    const inner = match[1];
    const topLevelMatch = inner.match(/^(\d+(?:\.\d+)*)\.?\s+(.+)$/);
    if (!topLevelMatch) {
      throw new Error(`Unable to parse top-level heading: ${line}`);
    }
    const [, number, headingText] = topLevelMatch;
    const node = newSectionNode(number, headingText, line, null);
    sectionStack.length = 0;
    document.sections.push(node);
    sectionStack.push(node);
    currentNode = node;
    continue;
  }

  match = trimmed.match(/^(\d+(?:\.\d+)*)(?:\.)?\s+(.+)$/);
  if (match) {
    bulletStack.length = 0;
    const [, number, headingText] = match;
    const depth = number.split('.').length;
    if (depth <= 1) {
      throw new Error(`Unexpected non-top-level heading depth for: ${line}`);
    }
    while (sectionStack.length >= depth) {
      sectionStack.pop();
    }
    if (sectionStack.length !== depth - 1) {
      throw new Error(`Missing parent section for heading: ${line}`);
    }
    const parentNode = sectionStack[sectionStack.length - 1];
    const node = newSectionNode(number, headingText, line, parentNode.authority);
    parentNode.subsections.push(node);
    sectionStack.push(node);
    currentNode = node;
    continue;
  }

  if (trimmed.startsWith('|')) {
    if (!currentNode) {
      throw new Error(`Encountered a table outside of any section: ${line}`);
    }

    bulletStack.length = 0;
    const tableLines = [];
    while (index < lines.length && lines[index].trim().startsWith('|')) {
      tableLines.push(lines[index]);
      index += 1;
    }
    index -= 1;

    if (tableLines.length < 3) {
      throw new Error('Encountered a malformed table.');
    }

    const columns = splitTableRow(tableLines[0]).map((header) => toSnakeCase(header));
    const rows = [];

    for (let rowIndex = 2; rowIndex < tableLines.length; rowIndex += 1) {
      const cells = splitTableRow(tableLines[rowIndex]);
      const row = {};
      for (let cellIndex = 0; cellIndex < columns.length; cellIndex += 1) {
        const header = columns[cellIndex];
        const cellValue = cellIndex < cells.length ? cells[cellIndex] : '';
        row[header] = convertScalarValue(cellValue);
      }
      if (Object.prototype.hasOwnProperty.call(row, 'xp_used_range')) {
        const bounds = parseRangeBounds(String(row.xp_used_range));
        if (bounds) {
          row.xp_used_min = bounds.min;
          row.xp_used_max = bounds.max;
        }
      }
      rows.push(row);
    }

    currentNode.entries.push({
      type: 'table',
      title: currentNode.title,
      columns,
      rows
    });
    continue;
  }

  match = line.match(/^(\s*)-\s+(.+)$/);
  if (match) {
    const indent = match[1].length;
    const entry = newBulletEntry(line);

    while (bulletStack.length && bulletStack[bulletStack.length - 1].indent >= indent) {
      bulletStack.pop();
    }

    if (bulletStack.length) {
      bulletStack[bulletStack.length - 1].entry.children.push(entry);
    } else if (currentNode) {
      currentNode.entries.push(entry);
    } else {
      document.preamble.push(entry);
    }

    bulletStack.push({ indent, entry });
    continue;
  }

  bulletStack.length = 0;
  const trimmedLine = line.trim();
  const labeledMatch = trimmedLine.match(/^([^:]+):\s*(.+)$/);
  const entry = labeledMatch
    ? newLabeledRuleEntry(trimmedLine, labeledMatch[1], labeledMatch[2])
    : newStatementEntry(trimmedLine);

  if (currentNode) {
    currentNode.entries.push(entry);
  } else {
    document.preamble.push(entry);
  }
}

fs.writeFileSync(outputPath, `${JSON.stringify(document, null, 2)}\n`, 'utf8');
console.log(`Wrote ${outputPath}`);
